import{_ as a,o,c as r,ae as i}from"./chunks/framework.Czhw_PXq.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"releases/1.8.0.md","filePath":"releases/1.8.0.md"}'),t={name:"releases/1.8.0.md"};function d(n,e,c,s,l,u){return o(),r("div",null,[...e[0]||(e[0]=[i('<h3 id="highlights" tabindex="-1">Highlights <a class="header-anchor" href="#highlights" aria-label="Permalink to &quot;Highlights&quot;">​</a></h3><p>This release introduces a first-principles language support foundation for Notemd: UI locale and task output language are now treated as separate concerns and resolved through a unified policy layer. This removes scattered language branches across task code paths and makes behavior consistent for processing, research, generation, Mermaid summaries, and translation-related flows.</p><p>It also upgrades maintainability and release safety. Notemd now has reproducible baseline/compare regression scripts with preserved before/after evidence, plus build/test isolation for the reference repository under <code>ref/**</code>. If you are maintaining or extending this plugin, this version significantly lowers regression risk while preparing the codebase for future language expansion.</p><h3 id="breaking-changes" tabindex="-1">Breaking Changes <a class="header-anchor" href="#breaking-changes" aria-label="Permalink to &quot;Breaking Changes&quot;">​</a></h3><ul><li><strong>No user-facing migration is required</strong>: Existing installations automatically fall back to <code>uiLocale: auto</code> and continue using prior task language settings. No manual config migration is needed after upgrade.</li></ul><h3 id="new-features" tabindex="-1">New Features <a class="header-anchor" href="#new-features" aria-label="Permalink to &quot;New Features&quot;">​</a></h3><ul><li><code>feat</code>: Added a dedicated language domain model (<code>uiLocale</code> + task language policy) to centralize language decisions.</li><li><code>feat</code>: Added UI i18n infrastructure with centralized locale catalogs for all supported UI locales (<code>en</code>, <code>ar</code>, <code>de</code>, <code>es</code>, <code>fa</code>, <code>fr</code>, <code>id</code>, <code>it</code>, <code>ja</code>, <code>ko</code>, <code>nl</code>, <code>pl</code>, <code>pt</code>, <code>pt-BR</code>, <code>ru</code>, <code>th</code>, <code>tr</code>, <code>uk</code>, <code>vi</code>, <code>zh-CN</code>, <code>zh-TW</code>), fallback chaining, and string interpolation.</li><li><code>feat</code>: Migrated high-impact settings/sidebar/error/runtime copy to shared i18n strings.</li><li><code>feat</code>: Added locale-aware time formatting and RTL-safe CSS guards for multilingual rendering robustness.</li><li><code>feat</code>: Added scripted regression workflow (<code>regression:language-baseline</code>, <code>regression:language-compare</code>) for reproducible before/after verification.</li></ul><h3 id="bug-fixes" tabindex="-1">Bug Fixes <a class="header-anchor" href="#bug-fixes" aria-label="Permalink to &quot;Bug Fixes&quot;">​</a></h3><ul><li><code>fix</code>: Fixed inconsistent task-language behavior caused by scattered language resolution logic across prompt/process/search/translate paths.</li><li><code>fix</code>: Fixed build instability when cloning a reference project under <code>ref/</code> by excluding <code>ref/**</code> from TypeScript/Jest/ESLint scopes.</li><li><code>fix</code>: Fixed several runtime UI notice paths that previously bypassed centralized language handling.</li></ul><h3 id="refactors-and-chores" tabindex="-1">Refactors And Chores <a class="header-anchor" href="#refactors-and-chores" aria-label="Permalink to &quot;Refactors And Chores&quot;">​</a></h3><ul><li><code>refactor</code>: Consolidated task language resolution into a shared policy layer and wired all main execution paths to it.</li><li><code>refactor</code>: Added i18n helper modules for locale normalization, fallback merge, and formatting.</li><li><code>chore</code>: Added targeted tests for language policy, i18n fallback behavior, and locale formatting.</li><li><code>chore</code>: Added baseline artifacts and release handoff docs for reproducible verification.</li><li><code>docs</code>: Updated <code>README.md</code> and <code>README_zh.md</code> with language architecture, regression workflow, and bilingual release process requirements.</li></ul><h3 id="contributors" tabindex="-1">Contributors <a class="header-anchor" href="#contributors" aria-label="Permalink to &quot;Contributors&quot;">​</a></h3><p>Thanks to <code>@Jacobinwwey</code> for driving the language-support architecture, migration, regression harness, and documentation updates.</p>',13)])])}const f=a(t,[["render",d]]);export{h as __pageData,f as default};
